import type { PlatformConfig } from "../platform.js";
/**
 * Switch the plugin's active organization to `<clerkOrganizationId>`:
 *
 *   switchOrg <clerkOrganizationId>
 *     {"event":"switched","status":"switched"|"already-aligned","clerkOrganizationId":"...","organizationName":"..."}
 *     {"event":"not-member","clerkOrganizationId":"..."}   // user isn't in that org
 *
 * Discovering which org to pass is the `list_organizations` MCP tool's job (the
 * agent reads it directly); this command only performs the switch. On success
 * the new org's API key is written to credentials.json (never printed) and the
 * active Studio pointer is cleared. The live browser does NOT flip on its own;
 * it follows on the next Studio open (a fresh session whose StudioOrgGate runs
 * the client-side `setActive`) or via the in-app org switcher.
 *
 * Free-form logs go to stderr; stdout stays a parseable JSONL stream.
 */
export declare function runSwitchOrg(platform: PlatformConfig): Promise<void>;
